import{_ as n,o as a,c as t,ag as i}from"./chunks/framework.DXGyWiRo.js";const r="/images/schrift018.jpg",s="/images/schrift019.jpg",b=JSON.parse('{"title":"Schriftübung 9","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/schrift09.md","filePath":"lektionen/schrift09.md"}'),o={name:"lektionen/schrift09.md"};function l(h,e,u,d,c,p){return a(),t("div",null,[...e[0]||(e[0]=[i('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="schriftubung-9" tabindex="-1">Schriftübung 9 <a class="header-anchor" href="#schriftubung-9" aria-label="Permalink to &quot;Schriftübung 9&quot;">​</a></h1><h3 id="worttrennung" tabindex="-1">Worttrennung <a class="header-anchor" href="#worttrennung" aria-label="Permalink to &quot;Worttrennung&quot;">​</a></h3><p>Innerhalb eines Satzes (einer Vershälfte) findet Worttrennung in der Schrift nur statt, wenn ein Wort mit</p><ul><li>Vokal</li><li>Anusvāra (ṃ)</li><li>Visarga (ḥ)</li></ul><p>schließt und das folgende Wort konsonantisch anlautet. Ebenso in den Fällen, in denen nach den Satzsandhiregeln ein Hiatus zwischen Vokalen entsteht.</p><h3 id="interpunktion" tabindex="-1">Interpunktion <a class="header-anchor" href="#interpunktion" aria-label="Permalink to &quot;Interpunktion&quot;">​</a></h3><p>Das Ende eines Satzes wird in Prosa mit | (ardhadaṇḍa m.) bezeichnet. In Versen bezeichnet | das Ende der Halbstrophe, das Ende der Strophe bezeichnet || (daṇḍa m.). In Prosa bezeichnet || einen größeren Einschnitt (z.B. das Ende eines Absatzes). Die Verszählung wird zwischen zwei || gesetzt, z.B. ||१||.</p><h3 id="abkurzung" tabindex="-1">Abkürzung <a class="header-anchor" href="#abkurzung" aria-label="Permalink to &quot;Abkürzung&quot;">​</a></h3><p>Abkürzungszeichen (z.B. in Angaben von Werken) ist °, z.B. पा° = pā(ṇinīye) = &quot;Im Grammatiklehrwerk des Pāṇini&quot;.</p><h3 id="weitere-vokale-in-anfangsstellung" tabindex="-1">Weitere Vokale in Anfangsstellung <a class="header-anchor" href="#weitere-vokale-in-anfangsstellung" aria-label="Permalink to &quot;Weitere Vokale in Anfangsstellung&quot;">​</a></h3><p><img src="'+r+'" alt=""></p><p><img src="'+s+'" alt=""></p><p>Beachten Sie, dass a, ā, o, au nch demselben Grundschema geschrieben werden.</p><h2 id="ubung" tabindex="-1">Übung <a class="header-anchor" href="#ubung" aria-label="Permalink to &quot;Übung&quot;">​</a></h2><p>A) Schreiben Sie in Devanāgarī:</p><p>ṛṣayaḥ ekadṛṣṭiḥ ojas ṛcchati aitareya ṛte auṣadhaṃ ṛgvedaḥ eṣin aiśvaryaṃ oṣṭhapallavaḥ etat ṛṇam aitihāsikā aupamyaṃ ṛtvij evaṃvidha</p><p>B) Lesen und transliterieren Sie:</p><p>ए इ उ अ ऋ ई ऊ ओ ऐ आ औ ॠ अथ इष् उत् एक इन् ओत् अद् ऐश ऋध् ऊह् एध् ईश् उद्य औम् ऋण ऊढ इह उष् अद् अल् ॐ ओख् ऋच् ऐण उदङ् ऋणम् ईषत् ऊहनम् ऋषभ औषधम् ऐषमस् उपकरणम् ||</p>',19)])])}const m=n(o,[["render",l]]);export{b as __pageData,m as default};
